package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	mu      sync.Mutex
	balances map[string]int
}

func NewBank() *Bank {
	return &Bank{
		balances: make(map[string]int),
	}
}

func (b *Bank) Deposit(account string, amount int) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.balances[account] += amount
}

func (b *Bank) Withdraw(account string, amount int) bool {
	b.mu.Lock()
	defer b.mu.Unlock()
	if b.balances[account] >= amount {
		b.balances[account] -= amount
		return true
	}
	return false
}

func (b *Bank) CheckBalance(account string) int {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.balances[account]
}

func main() {
	bank := NewBank()
	var wg sync.WaitGroup

	wg.Add(2)
	go func() {
		defer wg.Done()
		bank.Deposit("Alice", 100)
	}()

	go func() {
		defer wg.Done()
		if bank.Withdraw("Alice", 50) {
			fmt.Println("Withdrawal successful")
		} else {
			fmt.Println("Insufficient funds")
		}
	}()

	wg.Wait()
	fmt.Println("Alice's balance:", bank.CheckBalance("Alice"))
}